namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null);
    Task<ShipmentDto?> GetShipmentAsync(int id);
    Task<TrackingResultDto?> TrackShipmentAsync(string trackingNumber);
    Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto);
    Task UpdateStatusAsync(int id, UpdateShipmentStatusDto dto);
