using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var url = "/api/shipments";
        if (!string.IsNullOrEmpty(statusFilter))
            url += $"?status={Uri.EscapeDataString(statusFilter)}";

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        return await http.GetFromJsonAsync<ShipmentDto>($"/api/shipments/{id}");
    }

    public async Task<TrackingResultDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<TrackingResultDto>();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", dto);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }

    public async Task UpdateStatusAsync(int id, UpdateShipmentStatusDto dto)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", dto);
        response.EnsureSuccessStatusCode();
    }
}

