using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
        {
            query = query.Where(s => s.Status == status);
        }

        return await query.OrderByDescending(s => s.CreatedDate)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<TrackingResultDto?> TrackShipmentAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

        if (shipment is null) return null;

        return new TrackingResultDto
        {
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status.ToString(),
            CreatedDate = shipment.CreatedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            RecipientName = shipment.RecipientName
        };
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var lastShipment = await db.Shipments
            .OrderByDescending(s => s.Id)
            .FirstOrDefaultAsync();

        var nextNumber = (lastShipment?.Id ?? 0) + 1;
        var trackingNumber = $"SHP-{DateTime.UtcNow.Year}{nextNumber:D4}";

        var shipment = new Shipment
        {
            TrackingNumber = trackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            RecipientEmail = dto.RecipientEmail,
            Notes = dto.Notes
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();

        return MapToDto(shipment);
    }

    public async Task UpdateStatusAsync(int id, UpdateShipmentStatusDto dto)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new KeyNotFoundException($"Shipment {id} not found");

        if (Enum.TryParse<ShipmentStatus>(dto.Status, true, out var status))
        {
            shipment.Status = status;
        }

        if (dto.Notes is not null)
        {
            shipment.Notes = dto.Notes;
        }

        await db.SaveChangesAsync();
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status.ToString(),
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail,
        Notes = s.Notes
    };
}

