        <div class="col-md-8">
            <div class="card shadow">
                <div class="card-body p-4">
                    <h3 class="card-title text-center mb-3">Track Your Shipment</h3>
                    <div class="input-group input-group-lg">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260001)"
                               @bind="trackingNumber" @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment">
                            🔍 Track
                        </button>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <AuthorizeView>
        <Authorized>
            <div class="text-center">
                <a href="shipments" class="btn btn-success btn-lg me-2">📋 Shipments Dashboard</a>
                <a href="shipments/create" class="btn btn-outline-primary btn-lg">➕ New Shipment</a>
            </div>
        </Authorized>
        <NotAuthorized>
            <div class="text-center">
                <p class="text-muted mb-3">Sign in to manage shipments</p>
                <a href="Account/Login" class="btn btn-primary me-2">Login</a>
                <a href="Account/Register" class="btn btn-outline-secondary">Register</a>
            </div>
        </NotAuthorized>
    </AuthorizeView>
</div>

@code {
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private string trackingNumber = "";

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
        }
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") TrackShipment();
    }
}

