@page "/shipments"
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Shipments Dashboard</PageTitle>

<div class="container mt-4">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>📋 Shipments</h2>
        <a href="shipments/create" class="btn btn-primary">➕ New Shipment</a>
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Filter by Status:</label>
        <select class="form-select w-auto d-inline-block" @onchange="OnStatusFilterChanged">
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="PickedUp">Picked Up</option>
            <option value="InTransit">In Transit</option>
            <option value="OutForDelivery">Out For Delivery</option>
            <option value="Delivered">Delivered</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>

    @if (shipments is null)
    {
        <p><em>Loading shipments...</em></p>
    }
    else if (!shipments.Any())
    {
        <div class="alert alert-info">No shipments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in shipments)
                    {
                        <tr role="button" @onclick="() => ViewDetails(s.Id)" style="cursor:pointer;">
                            <td><code>@s.TrackingNumber</code></td>
                            <td>@s.Origin</td>
                            <td>@s.Destination</td>
                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@FormatStatus(s.Status)</span></td>
                            <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private List<ShipmentDto>? shipments;
    private string? currentFilter;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task OnStatusFilterChanged(ChangeEventArgs e)
    {
        currentFilter = e.Value?.ToString();
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync(currentFilter);
    }

    private void ViewDetails(int id)
    {
        Navigation.NavigateTo($"/shipments/{id}");
    }

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out For Delivery",
        _ => status
    };

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/shipments/create"
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Create Shipment</PageTitle>

<div class="container mt-4">
    <h2>➕ Create New Shipment</h2>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="CreateShipmentForm">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label class="form-label">Origin</label>
