@code {
    [Parameter] public int Id { get; set; }
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;

    private ShipmentDto? shipment;
    private string newStatus = "Pending";
    private string statusNotes = "";
    private bool isUpdating;
    private string? statusMessage;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        shipment = await ShipmentService.GetShipmentAsync(Id);
        if (shipment is not null)
            newStatus = shipment.Status;
    }

    private async Task UpdateStatus()
    {
        isUpdating = true;
        statusMessage = null;

        try
        {
            await ShipmentService.UpdateStatusAsync(Id, new UpdateShipmentStatusDto
            {
                Status = newStatus,
                Notes = string.IsNullOrWhiteSpace(statusNotes) ? null : statusNotes
            });

            shipment = await ShipmentService.GetShipmentAsync(Id);
            statusMessage = "Status updated successfully.";
            isError = false;
            statusNotes = "";
        }
        catch (Exception ex)
        {
            statusMessage = $"Error: {ex.Message}";
            isError = true;
        }
        finally
        {
            isUpdating = false;
        }
    }

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out For Delivery",
        _ => status
    };

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Cancelled" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track/{TrackingNumber?}"
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<div class="container mt-4">
    <h2 class="text-center mb-4">🔍 Track Your Shipment</h2>

    <div class="row justify-content-center mb-4">
        <div class="col-md-8">
            <div class="input-group input-group-lg">
                <input type="text" class="form-control" placeholder="Enter tracking number"
                       @bind="searchNumber" @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="Search">Track</button>
            </div>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="text-center"><em>Looking up shipment...</em></div>
    }
    else if (notFound)
    {
        <div class="alert alert-warning text-center">
            No shipment found with tracking number <strong>@TrackingNumber</strong>.
        </div>
    }
    else if (result is not null)
    {
        <div class="row justify-content-center">
            <div class="col-md-10">
                <div class="card shadow">
                    <div class="card-header bg-primary text-white">
                        <h4 class="mb-0">Shipment <code class="text-white">@result.TrackingNumber</code></h4>
                    </div>
                    <div class="card-body">
                        <div class="row mb-4">
                            <div class="col-md-6">
                                <dl>
                                    <dt>Origin</dt>
                                    <dd>@result.Origin</dd>
                                    <dt>Destination</dt>
                                    <dd>@result.Destination</dd>
                                </dl>
                            </div>
                            <div class="col-md-6">
                                <dl>
                                    <dt>Recipient</dt>
                                    <dd>@(result.RecipientName ?? "—")</dd>
                                    <dt>Estimated Delivery</dt>
                                    <dd>@(result.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>
                                    <dt>Shipped On</dt>
                                    <dd>@result.CreatedDate.ToString("MMM dd, yyyy")</dd>
                                </dl>
                            </div>
                        </div>

                        @{
                            var steps = new[] { "Pending", "PickedUp", "InTransit", "OutForDelivery", "Delivered" };
                            var currentIndex = Array.IndexOf(steps, result.Status);
                            var isCancelled = result.Status == "Cancelled";
                        }

                        @if (isCancelled)
                        {
                            <div class="alert alert-danger text-center">
                                <strong>❌ This shipment has been cancelled.</strong>
                            </div>
                        }
                        else
                        {
                            <h5 class="mb-3">Shipment Progress</h5>
                            <div class="progress mb-2" style="height: 24px;">
                                @{
                                    var pct = currentIndex >= 0 ? (int)((currentIndex / 4.0) * 100) : 0;
                                }
                                <div class="progress-bar bg-success" role="progressbar"
                                     style="width: @(pct)%;" aria-valuenow="@pct" aria-valuemin="0" aria-valuemax="100">
                                    @pct%
                                </div>
                            </div>
                            <div class="d-flex justify-content-between mt-2">
                                @for (int i = 0; i < steps.Length; i++)
                                {
                                    var step = steps[i];
                                    var isActive = i <= currentIndex;
                                    var isCurrent = i == currentIndex;
                                    <div class="text-center" style="flex:1;">
                                        <div class="@(isCurrent ? "fw-bold text-success" : isActive ? "text-success" : "text-muted")">
                                            @(isActive ? "✅" : "⬜") @FormatStatus(step)
                                        </div>
                                    </div>
                                }
                            </div>
                        }
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public string? TrackingNumber { get; set; }
    [Inject] private IShipmentService ShipmentService { get; set; } = default!;
    [Inject] private NavigationManager Navigation { get; set; } = default!;

    private TrackingResultDto? result;
    private bool isLoading;
    private bool notFound;
    private string searchNumber = "";

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchNumber = TrackingNumber;
            await LoadTracking();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber) && TrackingNumber != result?.TrackingNumber)
        {
            searchNumber = TrackingNumber;
            await LoadTracking();
        }
    }

    private async Task LoadTracking()
    {
        isLoading = true;
        notFound = false;
        result = null;

        result = await ShipmentService.TrackShipmentAsync(TrackingNumber!);
        notFound = result is null;
        isLoading = false;
    }

    private void Search()
    {
        if (!string.IsNullOrWhiteSpace(searchNumber))
        {
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(searchNumber.Trim())}");
        }
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") Search();
    }

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out For Delivery",
        _ => status
    };
}

