1. @page "/track/{TrackingNumber?}"
2. @rendermode InteractiveAuto
3. 
4. <PageTitle>Track Shipment</PageTitle>
5. 
6. <div class="container mt-4">
7.     <h2 class="text-center mb-4">🔍 Track Your Shipment</h2>
8. 
9.     <div class="row justify-content-center mb-4">
10.         <div class="col-md-8">
11.             <div class="input-group input-group-lg">
12.                 <input type="text" class="form-control" placeholder="Enter tracking number"
13.                        @bind="searchNumber" @onkeydown="HandleKeyDown" />
14.                 <button class="btn btn-primary" @onclick="Search">Track</button>
15.             </div>
16.         </div>
17.     </div>
18. 
19.     @if (isLoading)
20.     {
21.         <div class="text-center"><em>Looking up shipment...</em></div>
22.     }
23.     else if (notFound)
24.     {
25.         <div class="alert alert-warning text-center">
26.             No shipment found with tracking number <strong>@TrackingNumber</strong>.
27.         </div>
28.     }
29.     else if (result is not null)
30.     {
31.         <div class="row justify-content-center">
32.             <div class="col-md-10">
33.                 <div class="card shadow">
34.                     <div class="card-header bg-primary text-white">
35.                         <h4 class="mb-0">Shipment <code class="text-white">@result.TrackingNumber</code></h4>
36.                     </div>
37.                     <div class="card-body">
38.                         <div class="row mb-4">
39.                             <div class="col-md-6">
40.                                 <dl>
41.                                     <dt>Origin</dt>
42.                                     <dd>@result.Origin</dd>
43.                                     <dt>Destination</dt>
44.                                     <dd>@result.Destination</dd>
45.                                 </dl>
46.                             </div>
47.                             <div class="col-md-6">
48.                                 <dl>
49.                                     <dt>Recipient</dt>
50.                                     <dd>@(result.RecipientName ?? "—")</dd>
51.                                     <dt>Estimated Delivery</dt>
52.                                     <dd>@(result.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>
53.                                     <dt>Shipped On</dt>
54.                                     <dd>@result.CreatedDate.ToString("MMM dd, yyyy")</dd>
55.                                 </dl>
56.                             </div>
57.                         </div>
58. 
59.                         @{
60.                             var steps = new[] { "Pending", "PickedUp", "InTransit", "OutForDelivery", "Delivered" };
61.                             var currentIndex = Array.IndexOf(steps, result.Status);
62.                             var isCancelled = result.Status == "Cancelled";
63.                         }
64. 
65.                         @if (isCancelled)
66.                         {
67.                             <div class="alert alert-danger text-center">
68.                                 <strong>❌ This shipment has been cancelled.</strong>
69.                             </div>
70.                         }
71.                         else
72.                         {
73.                             <h5 class="mb-3">Shipment Progress</h5>
74.                             <div class="progress mb-2" style="height: 24px;">
75.                                 @{
76.                                     var pct = currentIndex >= 0 ? (int)((currentIndex / 4.0) * 100) : 0;
77.                                 }
78.                                 <div class="progress-bar bg-success" role="progressbar"
79.                                      style="width: @(pct)%;" aria-valuenow="@pct" aria-valuemin="0" aria-valuemax="100">
80.                                     @pct%
81.                                 </div>
82.                             </div>
83.                             <div class="d-flex justify-content-between mt-2">
84.                                 @for (int i = 0; i < steps.Length; i++)
85.                                 {
86.                                     var step = steps[i];
87.                                     var isActive = i <= currentIndex;
88.                                     var isCurrent = i == currentIndex;
89.                                     <div class="text-center" style="flex:1;">
90.                                         <div class="@(isCurrent ? "fw-bold text-success" : isActive ? "text-success" : "text-muted")">
