 using ShipmentTracker.Client.Models;
 using ShipmentTracker.Client.Services;

 namespace ShipmentTracker.Endpoints;

 public static class ShipmentEndpoints
 {
     public static void MapShipmentEndpoints(this WebApplication app)
     {
         var api = app.MapGroup("/api/shipments");

         api.MapGet("/", async (string? status, IShipmentService service) =>
         {
             var shipments = await service.GetShipmentsAsync(status);
             return Results.Ok(shipments);
         }).RequireAuthorization();

         api.MapGet("/{id:int}", async (int id, IShipmentService service) =>
         {
             var shipment = await service.GetShipmentAsync(id);
             return shipment is null ? Results.NotFound() : Results.Ok(shipment);
         }).RequireAuthorization();

         api.MapPost("/", async (CreateShipmentDto dto, IShipmentService service) =>
         {
             var shipment = await service.CreateShipmentAsync(dto);
             return Results.Created($"/api/shipments/{shipment.Id}", shipment);
         }).RequireAuthorization();

         api.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusDto dto, IShipmentService service) =>
         {
             await service.UpdateStatusAsync(id, dto);
             return Results.NoContent();
         }).RequireAuthorization();

         api.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
         {
             var result = await service.TrackShipmentAsync(trackingNumber);
             return result is null ? Results.NotFound() : Results.Ok(result);
         });
     }
 }

