 @code {
     [Parameter] public int Id { get; set; }
     [Inject] private IShipmentService ShipmentService { get; set; } = default!;

     private ShipmentDto? shipment;
     private string newStatus = "Pending";
     private string statusNotes = "";
     private bool isUpdating;
     private string? statusMessage;
     private bool isError;

     protected override async Task OnInitializedAsync()
     {
         shipment = await ShipmentService.GetShipmentAsync(Id);
         if (shipment is not null)
             newStatus = shipment.Status;
     }

     private async Task UpdateStatus()
     {
         isUpdating = true;
         statusMessage = null;

         try
         {
             await ShipmentService.UpdateStatusAsync(Id, new UpdateShipmentStatusDto
             {
                 Status = newStatus,
                 Notes = string.IsNullOrWhiteSpace(statusNotes) ? null : statusNotes
             });

             shipment = await ShipmentService.GetShipmentAsync(Id);
             statusMessage = "Status updated successfully.";
             isError = false;
             statusNotes = "";
         }
         catch (Exception ex)
         {
             statusMessage = $"Error: {ex.Message}";
             isError = true;
         }
         finally
         {
             isUpdating = false;
         }
     }

     private static string FormatStatus(string status) => status switch
     {
         "PickedUp" => "Picked Up",
         "InTransit" => "In Transit",
         "OutForDelivery" => "Out For Delivery",
         _ => status
     };

     private static string GetStatusBadgeClass(string status) => status switch
     {
         "Pending" => "bg-secondary",
         "PickedUp" => "bg-info",
         "InTransit" => "bg-primary",
         "OutForDelivery" => "bg-warning text-dark",
         "Delivered" => "bg-success",
         "Cancelled" => "bg-danger",
         _ => "bg-secondary"
     };
 }

